/**
 * HealthMonitor — Scans a codebase and produces coherency health reports
 *
 * Walks source files, scores each one through the Oracle's coherency engine,
 * identifies weak spots, and flags covenant violations.
 */

const fs = require('node:fs');
const path = require('node:path');

const SOURCE_EXTENSIONS = new Set([
  '.js', '.mjs', '.cjs', '.ts', '.tsx',
  '.py', '.go', '.rs', '.rb', '.java',
  '.sh', '.bash',
]);

const IGNORE_DIRS = new Set([
  'node_modules', '.git', 'dist', 'build', 'coverage',
  '.remembrance', '__pycache__', '.next', '.nuxt', 'vendor',
]);

class HealthMonitor {
  #connector;
  #threshold;

  constructor(connector, options = {}) {
    this.#connector = connector;
    this.#threshold = options.threshold ?? parseFloat(process.env.ORACLE_THRESHOLD || '0.6');
  }

  /** Scan a directory and return a full health report */
  async scan(targetDir, options = {}) {
    const dir = path.resolve(targetDir || process.cwd());
    const files = this.#collectFiles(dir, options.extensions);
    const results = [];
    let totalScore = 0;
    let covenantViolations = 0;

    for (const filePath of files) {
      const result = await this.#analyzeFile(filePath);
      results.push(result);
      totalScore += result.coherency.total;
      if (!result.covenant.sealed) covenantViolations++;
    }

    const avgScore = files.length > 0 ? totalScore / files.length : 0;

    const report = {
      timestamp: new Date().toISOString(),
      directory: dir,
      summary: {
        filesScanned: files.length,
        averageCoherency: Math.round(avgScore * 1000) / 1000,
