// ─── Configuration Defaults ───

const DEFAULT_CONFIG = {
  minCoherence: 0.7,           // Files below this get healed
  autoMergeThreshold: 0.9,     // Auto-merge PRs above this coherence
  maxFilesPerRun: 50,          // Safety limit
  maxFileSizeBytes: 100000,    // Skip files larger than 100KB
  maxSerfLoops: 3,             // SERF iterations per file
  targetCoherence: 0.95,       // SERF target per file
  includeExtensions: ['.js', '.ts', '.py', '.go', '.rs', '.java', '.jsx', '.tsx'],
  excludeDirs: ['node_modules', '.git', 'dist', 'build', 'coverage', '.remembrance', 'vendor', '__pycache__'],
  excludeFiles: ['package-lock.json', 'yarn.lock', 'pnpm-lock.yaml'],
};

// ─── File Scanner ───

/**
 * Recursively scan a directory for source files matching config criteria.
 *
 * @param {string} rootDir - Root directory to scan
 * @param {object} config - Scanner configuration
 * @returns {string[]} Array of absolute file paths
 */
function scanDirectory(rootDir, config = {}) {
  const opts = { ...DEFAULT_CONFIG, ...config };
  const files = [];

  function walk(dir) {
    if (files.length >= opts.maxFilesPerRun) return;

    let entries;
    try {
      entries = readdirSync(dir);
    } catch {
      return; // Skip unreadable directories
    }

    for (const entry of entries) {
      if (files.length >= opts.maxFilesPerRun) break;

      const fullPath = join(dir, entry);
      let stat;
      try {
        stat = statSync(fullPath);
      } catch {
        continue; // Skip unreadable files
      }

      if (stat.isDirectory()) {
        if (!opts.excludeDirs.includes(entry)) {
          walk(fullPath);
        }
      } else if (stat.isFile()) {
        if (opts.excludeFiles.includes(entry)) continue;
        const ext = extname(entry);
        if (!opts.includeExtensions.includes(ext)) continue;
        if (stat.size > opts.maxFileSizeBytes) continue;
        files.push(fullPath);
      }
    }
  }

  walk(rootDir);
  return files;
}

// ─── Incremental (Git-Diff) Scanner ───

/**
 * Scan only files that changed since a given git ref (commit, branch, tag).
 * Falls back to full scanDirectory() if git is unavailable or the ref is invalid.
 *
 * @param {string} rootDir - Repository root (must be inside a git repo)
 * @param {object} config - Scanner configuration
 * @param {string} config.sinceRef - Git ref to diff against (default: HEAD~1)
 * @returns {{ files: string[], incremental: boolean, ref: string }}
 */
function scanIncremental(rootDir, config = {}) {
  const opts = { ...DEFAULT_CONFIG, ...config };
  const ref = opts.sinceRef || 'HEAD~1';

  try {
    // Get changed files (added, modified, renamed) since ref
    const raw = execFileSync('git', ['diff', '--name-only', '--diff-filter=AMR', ref], {
      cwd: rootDir,
      encoding: 'utf-8',
      timeout: 10000,
    });

    const changedPaths = raw.trim().split('\n').filter(Boolean);

    // Filter through the same criteria as scanDirectory
    const files = [];
    for (const relPath of changedPaths) {
      if (files.length >= opts.maxFilesPerRun) break;

      const ext = extname(relPath);
      if (!opts.includeExtensions.includes(ext)) continue;

      const parts = relPath.split('/');
      if (parts.some(p => opts.excludeDirs.includes(p))) continue;

      const fileName = parts[parts.length - 1];
      if (opts.excludeFiles.includes(fileName)) continue;

      const fullPath = join(rootDir, relPath);
      try {
        const stat = statSync(fullPath);
        if (!stat.isFile() || stat.size > opts.maxFileSizeBytes) continue;
        files.push(fullPath);
      } catch {
        continue; // File was deleted or unreadable
      }
    }

    return { files, incremental: true, ref };
  } catch {
    // Git not available or ref invalid — fall back to full scan
    return { files: scanDirectory(rootDir, opts), incremental: false, ref };
  }
}

// ─── Safe File Reader ───

/**
 * Read a file with a size guard. Checks file size via stat before reading
 * to avoid allocating large buffers for files that exceed the limit.
 * Returns { code } on success or { error } if the file is too large or unreadable.
 *
 * @param {string} filePath - Absolute path
 * @param {number} maxBytes - Maximum file size in bytes
 * @returns {{ code?: string, error?: string }}
 */
function safeReadFile(filePath, maxBytes) {
  try {
    const stat = statSync(filePath);
    if (stat.size > maxBytes) {
      return { error: `File too large (${stat.size} bytes, limit ${maxBytes})` };
    }
    return { code: readFileSync(filePath, 'utf-8') };
  } catch (err) {
    return { error: `Read failed: ${err.message}` };
  }
}

// ─── File Coherence Evaluation ───

/**
 * Evaluate a single file's coherence across all SERF dimensions.
 *
 * @param {string} filePath - Absolute path to the file
 * @param {object} config - Evaluation config
 * @returns {object} { path, language, coherence, dimensions, size, lines }
 */
function evaluateFile(filePath, config = {}) {
  const opts = { ...DEFAULT_CONFIG, ...config };
  const { code, error } = safeReadFile(filePath, opts.maxFileSizeBytes);
  if (error) {
    return { path: filePath, error, coherence: 0 };
  }

  if (!code.trim()) {
    return { path: filePath, error: 'Empty file', coherence: 0 };
  }

  const language = detectLanguageFromPath(filePath) || detectLanguage(code);
  const observation = observeCoherence(code, { language });

  // Covenant check — does this file pass the 15 principles?
  // Skip covenant check for test files to avoid false positives on test input
  // strings that intentionally contain destructive patterns (Issue 2 fix).
  const isTestFile = /\.(test|spec)\.(js|ts|mjs|cjs)$/.test(filePath);
  const covenant = isTestFile
    ? { sealed: true, violations: [], principlesPassed: 15, totalPrinciples: 15 }
    : covenantCheck(code, { language });

  return {
    path: filePath,
    language,
    coherence: observation.composite,
    dimensions: observation.dimensions,
    covenantSealed: covenant.sealed,
    covenantViolations: covenant.violations || [],
    size: code.length,
    lines: code.split('\n').length,
  };
}

// ─── Parallel File Evaluation ───

/**
 * Evaluate multiple files in parallel using worker threads.
 * Spawns up to `concurrency` workers, each evaluating a single file.
 * Returns a Promise that resolves to an array of evaluation results.
 *
 * @param {string[]} filePaths - Absolute file paths to evaluate
 * @param {object} config - Evaluation config passed to each worker
 * @param {number} config.concurrency - Max parallel workers (default: 4)
 * @returns {Promise<object[]>} Array of evaluation results
 */
function evaluateFilesParallel(filePaths, config = {}) {
  const { Worker } = require('worker_threads');
  const concurrency = config.concurrency || 4;
  const workerPath = join(__dirname, 'evalWorker.js');
  const workerTimeoutMs = config.workerTimeoutMs || 30000; // 30s per worker

  return new Promise((resolve) => {
    const results = [];
    let nextIndex = 0;
    let active = 0;
    let resolved = false;

    function finish() {
      if (!resolved) {
        resolved = true;
        resolve(results);
      }
    }

    // Global safety timeout: don't hang forever even if workers misbehave
    const globalTimeout = setTimeout(() => {
      if (!resolved) {
        // Fill in missing results with timeout errors
        for (let i = 0; i < filePaths.length; i++) {
          if (!results[i]) {
            results[i] = { path: filePaths[i], error: 'Worker timed out', coherence: 0 };
          }
        }
        finish();
      }
    }, workerTimeoutMs * filePaths.length + 5000);

    function spawnNext() {
      if (nextIndex >= filePaths.length && active === 0) {
        clearTimeout(globalTimeout);
        finish();
        return;
      }
      while (active < concurrency && nextIndex < filePaths.length) {
        const idx = nextIndex++;
        active++;
        const worker = new Worker(workerPath, {
          workerData: { filePath: filePaths[idx], config },
        });

        // Per-worker timeout to prevent individual hangs
        const workerTimer = setTimeout(() => {
          worker.terminate();
          if (!results[idx]) {
            results[idx] = { path: filePaths[idx], error: 'Worker timed out', coherence: 0 };
          }
        }, workerTimeoutMs);

        worker.on('message', (result) => {
          results[idx] = result;
        });
        worker.on('error', (err) => {
          results[idx] = { path: filePaths[idx], error: `Worker error: ${err.message}`, coherence: 0 };
          // Note: 'exit' event will also fire after 'error', so active-- happens there
        });
        worker.on('exit', () => {
          clearTimeout(workerTimer);
          active--;
          spawnNext();
        });
      }
    }

    if (filePaths.length === 0) {
      clearTimeout(globalTimeout);
      finish();
      return;
    }
    spawnNext();
  });
}

// ─── Codebase Snapshot ───

/**
 * Take a coherence snapshot of a codebase.
 * When config.incremental is true and a git ref is available, only evaluates
 * files that changed since that ref. Falls back to full scan otherwise.
 *
 * @param {string} rootDir - Root directory to scan
 * @param {object} config - Configuration overrides
 * @param {boolean} config.incremental - Use git-diff to scan only changed files
 * @param {string} config.sinceRef - Git ref to diff against (default: HEAD~1)
 * @returns {object} { files, aggregate, belowThreshold, timestamp, incremental }
 */
function takeSnapshot(rootDir, config = {}) {
  const opts = { ...DEFAULT_CONFIG, ...config };

  let filePaths;
  let incrementalMeta = null;
  if (opts.incremental) {
    const result = scanIncremental(rootDir, opts);
    filePaths = result.files;
    incrementalMeta = { active: result.incremental, ref: result.ref, changedFiles: result.files.length };
  } else {
    filePaths = scanDirectory(rootDir, opts);
  }
  const files = [];

  for (const filePath of filePaths) {
    const evaluation = evaluateFile(filePath, opts);
    evaluation.relativePath = relative(rootDir, filePath);
    files.push(evaluation);
  }

  // Compute aggregate statistics
  const validFiles = files.filter(f => !f.error);
  const coherenceValues = validFiles.map(f => f.coherence);
  const avgCoherence = coherenceValues.length > 0
    ? coherenceValues.reduce((s, v) => s + v, 0) / coherenceValues.length
    : 0;

  const belowThreshold = validFiles.filter(f => f.coherence < opts.minCoherence);

  // Aggregate dimension scores
  const dimensionAverages = {};
  if (validFiles.length > 0) {
    const dims = Object.keys(validFiles[0].dimensions || {});
    for (const dim of dims) {
      const values = validFiles.map(f => f.dimensions?.[dim] || 0);
      dimensionAverages[dim] = values.reduce((s, v) => s + v, 0) / values.length;
    }
  }

  return {
    timestamp: new Date().toISOString(),
    rootDir,
    config: opts,
    files,
    aggregate: {
      totalFiles: files.length,
      validFiles: validFiles.length,
      errorFiles: files.filter(f => f.error).length,
      avgCoherence: Math.round(avgCoherence * 1000) / 1000,
      minCoherence: coherenceValues.length > 0 ? Math.min(...coherenceValues) : 0,
      maxCoherence: coherenceValues.length > 0 ? Math.max(...coherenceValues) : 0,
      dimensionAverages,
      covenantViolations: files.filter(f => !f.covenantSealed).length,
    },
    belowThreshold: belowThreshold.map(f => ({
      path: f.relativePath,
      coherence: f.coherence,
      dimensions: f.dimensions,
    })),
    incremental: incrementalMeta,
  };
}

/**
 * Async variant of takeSnapshot that evaluates files in parallel using worker threads.
 * Same output shape as takeSnapshot, but processes files concurrently for speed.
 *
 * @param {string} rootDir - Root directory to scan
 * @param {object} config - Configuration overrides
 * @param {number} config.concurrency - Max parallel workers (default: 4)
 * @returns {Promise<object>} Same shape as takeSnapshot result
 */
async function takeSnapshotAsync(rootDir, config = {}) {
  const opts = { ...DEFAULT_CONFIG, ...config };

  let filePaths;
  let incrementalMeta = null;
  if (opts.incremental) {
    const result = scanIncremental(rootDir, opts);
    filePaths = result.files;
    incrementalMeta = { active: result.incremental, ref: result.ref, changedFiles: result.files.length };
  } else {
    filePaths = scanDirectory(rootDir, opts);
  }

  // Evaluate all files in parallel
  const rawResults = await evaluateFilesParallel(filePaths, opts);
  const files = rawResults.map((evaluation, i) => {
    evaluation.relativePath = relative(rootDir, filePaths[i]);
    return evaluation;
  });

  // Same aggregate computation as takeSnapshot
  const validFiles = files.filter(f => !f.error);
  const coherenceValues = validFiles.map(f => f.coherence);
  const avgCoherence = coherenceValues.length > 0
    ? coherenceValues.reduce((s, v) => s + v, 0) / coherenceValues.length
    : 0;

  const belowThreshold = validFiles.filter(f => f.coherence < opts.minCoherence);

  const dimensionAverages = {};
  if (validFiles.length > 0) {
    const dims = Object.keys(validFiles[0].dimensions || {});
    for (const dim of dims) {
      const values = validFiles.map(f => f.dimensions?.[dim] || 0);
      dimensionAverages[dim] = values.reduce((s, v) => s + v, 0) / values.length;
    }
  }

  return {
    timestamp: new Date().toISOString(),
    rootDir,
    config: opts,
    files,
    aggregate: {
      totalFiles: files.length,
      validFiles: validFiles.length,
      errorFiles: files.filter(f => f.error).length,
      avgCoherence: Math.round(avgCoherence * 1000) / 1000,
      minCoherence: coherenceValues.length > 0 ? Math.min(...coherenceValues) : 0,
      maxCoherence: coherenceValues.length > 0 ? Math.max(...coherenceValues) : 0,
      dimensionAverages,
      covenantViolations: files.filter(f => !f.covenantSealed).length,
    },
    belowThreshold: belowThreshold.map(f => ({
      path: f.relativePath,
      coherence: f.coherence,
      dimensions: f.dimensions,
    })),
    incremental: incrementalMeta,
    parallel: true,
  };
}

// ─── Healing Engine ───

/**
 * Heal a single file using the SERF reflection loop.
 * Returns the healed code, coherence improvement, and whisper explanation.
 *
 * @param {string} filePath - Absolute path to the file
 * @param {object} config - Healing configuration
 * @returns {object} { path, original, healed, improvement, whisper, changed }
 */
function healFile(filePath, config = {}) {
  const opts = { ...DEFAULT_CONFIG, ...config };

  const { code, error } = safeReadFile(filePath, opts.maxFileSizeBytes);
  if (error) {
    return { path: filePath, error, changed: false };
  }

  if (!code.trim()) {
    return { path: filePath, error: 'Empty file', changed: false };
  }

  const language = detectLanguageFromPath(filePath) || detectLanguage(code);

  // Run SERF reflection loop (with optional pattern examples)
  const reflectionOpts = {
    language,
    maxLoops: opts.maxSerfLoops,
    targetCoherence: opts.targetCoherence,
  };
  if (opts.patternExamples && opts.patternExamples.length > 0) {
    reflectionOpts.patternExamples = opts.patternExamples;
    reflectionOpts.cascadeBoost = 1.05; // Slight boost for pattern-guided healing
  }
  const result = reflectionLoop(code, reflectionOpts);

  // Sanitize SERF output to fix known transform bugs
  // (chain-breaking semicolons, bracket semicolons, HTML attribute spacing)
  result.code = sanitizeSerfOutput(result.code, code);

  // ─── SERF Equation Processing ───
  // After the reflection loop produces healed code, run the SERF equation
  // to further refine it using pattern library references and the full
  // retrocausal pull / void replenishment / cascade / damping pipeline.
  let serfResult = null;
  if (opts.enableSerf !== false) {
    try {
      // Find a healed reference from pattern library
      const storeDir = opts.rootDir ? join(opts.rootDir, '.remembrance') : null;
      const healedReference = (opts.patternExamples && opts.patternExamples[0])
        ? opts.patternExamples[0].code
        : null;

      serfResult = runSerf(result.code, healedReference, {
        language,
        storeDir,
        tags: [language, 'healed'].filter(Boolean),
        description: `Healing ${filePath}`,
        params: opts.serfParams || {},
      });

      // Use SERF-refined code if it improved overlap
      if (serfResult.improvement > 0 || serfResult.fixes.length > 0) {
        result.code = serfResult.code;
      }
    } catch {
      // SERF processing failure is non-fatal — use reflection loop output
    }
  }

  const changed = result.code !== code;

  return {
    path: filePath,
    relativePath: config.rootDir ? relative(config.rootDir, filePath) : filePath,
    language,
    original: {
      code,
      coherence: result.serf.I_AM,
    },
    healed: {
      code: result.code,
      coherence: result.coherence,
    },
    improvement: result.serf.improvement,
    dimensions: result.dimensions,
    whisper: serfResult?.whisper || result.whisper,
    healingSummary: result.healingSummary,
    healingPath: result.healingPath,
    loops: result.loops,
    changed,
    serfDiagnostics: serfResult ? {
      initialOverlap: serfResult.initialOverlap,
      finalOverlap: serfResult.finalOverlap,
      coherence: serfResult.coherence,
      decision: serfResult.decision,
      params: serfResult.serfParams,
      patternsUsed: serfResult.patternsUsed,
      iterations: serfResult.iterations,
    } : null,
  };
}

// ─── Full Reflector Run ───

/**
 * Run the full self-reflector on a codebase:
 * 1. Snapshot the codebase (evaluate all files)
 * 2. Identify files below coherence threshold
 * 3. Heal each file via SERF reflection
 * 4. Return a structured report with all changes
 *
 * @param {string} rootDir - Root directory to reflect on
 * @param {object} config - Configuration overrides
 * @returns {object} Full reflector report
 */
function reflect(rootDir, config = {}) {
  const opts = { ...DEFAULT_CONFIG, ...config };

  // Step 0: Seed pattern library on first run (no-op if already populated)
  try { seedPatternLibrary(rootDir); } catch { /* non-fatal */ }

  // Step 1: Take snapshot (or reuse pre-computed one to avoid redundant scans)
  const snapshot = opts._preSnapshot || takeSnapshot(rootDir, opts);

  // Step 2: Identify files needing healing
  const filesToHeal = snapshot.files
    .filter(f => !f.error && f.coherence < opts.minCoherence && f.covenantSealed)
    .sort((a, b) => a.coherence - b.coherence); // Worst first

  // Step 3: Heal each file (with optional pattern hook)
  const healings = [];
  for (const file of filesToHeal) {
    // Query pattern library for guidance before healing
    let patternContext = null;
    if (opts.usePatternHook !== false) {
      try {
        patternContext = hookBeforeHeal(file.path, { rootDir });
      } catch {
        // Pattern hook failure is non-fatal
      }
    }

    // Pass pattern examples to healFile so SERF can use them
    const healOpts = { ...opts, rootDir };
    if (patternContext?.patternGuided && patternContext.healingContext?.examples) {
      healOpts.patternExamples = patternContext.healingContext.examples;
    }

    // Dimension-targeted healing: detect weakest dimension and hint SERF
    if (file.dimensions) {
      const dimToStrategy = {
        simplicity: 'simplify',
        readability: 'readable',
        security: 'secure',
        unity: 'unify',
        correctness: 'correct',
      };
      let weakestDim = null;
      let weakestScore = 1;
      for (const [dim, score] of Object.entries(file.dimensions)) {
        if (score < weakestScore) {
          weakestScore = score;
          weakestDim = dim;
        }
      }
      if (weakestDim && weakestScore < 0.8 && dimToStrategy[weakestDim]) {
        healOpts.preferredStrategy = dimToStrategy[weakestDim];
      }
    }

    const healing = healFile(file.path, healOpts);
    if (healing.changed && healing.improvement > 0) {
      healing.patternGuided = patternContext?.patternGuided || false;
      healings.push(healing);

      // Record pattern hook usage
      if (patternContext) {
        try {
          recordPatternHookUsage(rootDir, {
            filePath: file.path,
            patternGuided: patternContext.patternGuided,
            patternName: patternContext.bestMatch?.name || null,
            improvement: healing.improvement,
          });
        } catch {
          // Recording failure is non-fatal
        }
      }

      // Submit healed code back to the pattern library so future
      // healings can reference proven patterns (closes the feedback loop)
      submitHealedPattern(healing, rootDir, {
        preferredStrategy: healOpts.preferredStrategy || null,
        patternGuided: patternContext?.patternGuided || false,
        patternName: patternContext?.bestMatch?.name || null,
      });
    }
  }

  // Step 4: Compute overall improvement
  const totalImprovement = healings.reduce((s, h) => s + h.improvement, 0);
  const avgImprovement = healings.length > 0 ? totalImprovement / healings.length : 0;

  // Step 5: Generate a collective whisper
  const collectiveWhisper = generateCollectiveWhisper(snapshot, healings);

  return {
    timestamp: snapshot.timestamp,
    rootDir,
    snapshot: {
      totalFiles: snapshot.aggregate.totalFiles,
      avgCoherence: snapshot.aggregate.avgCoherence,
      minCoherence: snapshot.aggregate.minCoherence,
      maxCoherence: snapshot.aggregate.maxCoherence,
      dimensionAverages: snapshot.aggregate.dimensionAverages,
      covenantViolations: snapshot.aggregate.covenantViolations,
    },
    healings: healings.map(h => ({
      path: h.relativePath,
      language: h.language,
      originalCoherence: h.original.coherence,
      healedCoherence: h.healed.coherence,
      improvement: h.improvement,
      whisper: h.whisper,
      healingSummary: h.healingSummary,
      loops: h.loops,
    })),
    healedFiles: healings.map(h => ({
      path: h.relativePath,
      absolutePath: h.path,
      code: h.healed.code,
    })),
    summary: {
      filesScanned: snapshot.aggregate.totalFiles,
      filesBelowThreshold: filesToHeal.length,
      filesHealed: healings.length,
      totalImprovement: Math.round(totalImprovement * 1000) / 1000,
      avgImprovement: Math.round(avgImprovement * 1000) / 1000,
      autoMergeRecommended: snapshot.aggregate.avgCoherence >= opts.autoMergeThreshold,
    },
    collectiveWhisper,
    config: opts,
  };
}

// ─── Collective Whisper ───

function generateCollectiveWhisper(snapshot, healings) {
  if (healings.length === 0) {
    const avg = snapshot.aggregate.avgCoherence;
    return {
      message: 'The codebase rests in coherence. No healing was needed this cycle.',
      overallHealth: avg >= 0.8 ? 'healthy' : avg >= 0.6 ? 'stable' : 'needs attention',
    };
  }

  // Find the dominant healing strategy across all files
  const strategyCounts = {};
  for (const h of healings) {
    if (h.healingPath) {
      for (const path of h.healingPath) {
        const strategy = path.split(':')[0].trim();
        strategyCounts[strategy] = (strategyCounts[strategy] || 0) + 1;
      }
    }
  }

  const dominant = Object.entries(strategyCounts)
    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'reflection';

  const messages = {
    simplify: `${healings.length} file(s) were simplified — complexity fell away, revealing cleaner structure.`,
    secure: `${healings.length} file(s) were hardened — security boundaries strengthened across the codebase.`,
    readable: `${healings.length} file(s) were clarified — the future reader will understand instantly.`,
    unify: `${healings.length} file(s) were harmonized — the codebase now speaks with one voice.`,
    correct: `${healings.length} file(s) were corrected — edge cases sealed, robustness improved.`,
    heal: `${healings.length} file(s) received full healing — all five threads wove together.`,
    reflection: `${healings.length} file(s) were refined through reflection.`,
  };

  return {
    message: messages[dominant] || messages.reflection,
    dominantStrategy: dominant,
    filesHealed: healings.length,
    overallHealth: snapshot.aggregate.avgCoherence >= 0.8 ? 'healthy'
      : snapshot.aggregate.avgCoherence >= 0.6 ? 'stable'
      : 'needs attention',
  };
}

// ─── Report Formatting ───

/**
 * Format a reflector report as human-readable text.
 */
function formatReport(report) {
  const lines = [];
  lines.push('╔══════════════════════════════════════════════════════╗');
  lines.push('║       Remembrance Self-Reflector Report             ║');
  lines.push('╚══════════════════════════════════════════════════════╝');
  lines.push('');
  lines.push(`Timestamp: ${report.timestamp}`);
  lines.push(`Root: ${report.rootDir}`);
  lines.push('');

  // Snapshot summary
  lines.push('── Codebase Snapshot ──');
  lines.push(`  Files scanned: ${report.snapshot.totalFiles}`);
  lines.push(`  Avg coherence: ${report.snapshot.avgCoherence.toFixed(3)}`);
  lines.push(`  Min coherence: ${report.snapshot.minCoherence.toFixed(3)}`);
  lines.push(`  Max coherence: ${report.snapshot.maxCoherence.toFixed(3)}`);
  if (report.snapshot.covenantViolations > 0) {
    lines.push(`  Covenant violations: ${report.snapshot.covenantViolations}`);
  }
  lines.push('');

  // Dimension averages
  if (report.snapshot.dimensionAverages) {
    lines.push('── Dimension Averages ──');
    for (const [dim, val] of Object.entries(report.snapshot.dimensionAverages)) {
      const bar = '\u2588'.repeat(Math.round(val * 20));
      const faded = '\u2591'.repeat(20 - Math.round(val * 20));
      lines.push(`  ${dim.padEnd(14)} ${bar}${faded} ${val.toFixed(3)}`);
    }
    lines.push('');
  }

  // Healings
  lines.push('── Healing Results ──');
  lines.push(`  Files below threshold: ${report.summary.filesBelowThreshold}`);
  lines.push(`  Files healed: ${report.summary.filesHealed}`);
  lines.push(`  Total improvement: +${report.summary.totalImprovement.toFixed(3)}`);
  lines.push(`  Avg improvement: +${report.summary.avgImprovement.toFixed(3)}`);
  lines.push('');

  if (report.healings.length > 0) {
    for (const h of report.healings) {
      lines.push(`  ${h.path}`);
      lines.push(`    ${h.originalCoherence.toFixed(3)} → ${h.healedCoherence.toFixed(3)} (+${h.improvement.toFixed(3)}) [${h.loops} loop(s)]`);
      lines.push(`    Whisper: "${h.whisper}"`);
      lines.push('');
    }
  }

  // Collective whisper
  lines.push('── Collective Whisper ──');
  lines.push(`  "${report.collectiveWhisper.message}"`);
  lines.push(`  Overall health: ${report.collectiveWhisper.overallHealth}`);
  if (report.summary.autoMergeRecommended) {
    lines.push('  Auto-merge: RECOMMENDED (high overall coherence)');
  }

  return lines.join('\n');
}

/**
 * Format a reflector report as a GitHub PR body (markdown).
 */
function formatPRBody(report) {
  const lines = [];
  lines.push('## Remembrance Pull: Healed Refinement');
  lines.push('');
  lines.push(`> ${report.collectiveWhisper.message}`);
  lines.push('');

  // Summary table
  lines.push('### Summary');
  lines.push('');
  lines.push('| Metric | Value |');
  lines.push('|--------|-------|');
  lines.push(`| Files scanned | ${report.snapshot.totalFiles} |`);
  lines.push(`| Avg coherence | ${report.snapshot.avgCoherence.toFixed(3)} |`);
  lines.push(`| Files below threshold | ${report.summary.filesBelowThreshold} |`);
  lines.push(`| Files healed | ${report.summary.filesHealed} |`);
  lines.push(`| Total improvement | +${report.summary.totalImprovement.toFixed(3)} |`);
  lines.push('');

  // Dimension averages
  if (report.snapshot.dimensionAverages) {
    lines.push('### Coherence Dimensions');
    lines.push('');
    for (const [dim, val] of Object.entries(report.snapshot.dimensionAverages)) {
      const filled = Math.round(val * 10);
      const bar = '\u2588'.repeat(filled) + '\u2591'.repeat(10 - filled);
      lines.push(`- **${dim}**: \`${bar}\` ${val.toFixed(3)}`);
    }
    lines.push('');
  }

  // Per-file changes
  if (report.healings.length > 0) {
    lines.push('### Healed Files');
    lines.push('');
    for (const h of report.healings) {
      lines.push(`#### \`${h.path}\``);
      lines.push(`- **Coherence**: ${h.originalCoherence.toFixed(3)} → ${h.healedCoherence.toFixed(3)} (+${h.improvement.toFixed(3)})`);
      lines.push(`- **Strategy**: ${h.healingSummary}`);
      lines.push(`- **Whisper**: *"${h.whisper}"*`);
      lines.push('');
    }
  }

  // Health assessment
  lines.push('### Health Assessment');
  lines.push('');
  lines.push(`Overall codebase health: **${report.collectiveWhisper.overallHealth}**`);
  if (report.summary.autoMergeRecommended) {
    lines.push('');
    lines.push('> This PR is recommended for auto-merge (high overall coherence).');
  }

  return lines.join('\n');
}

module.exports = {
  scanDirectory,
  scanIncremental,
  safeReadFile,
  evaluateFile,
  evaluateFilesParallel,
  takeSnapshot,
  takeSnapshotAsync,
  healFile,
  reflect,
  formatReport,
  formatPRBody,
  generateCollectiveWhisper,
  submitHealedPattern,
  DEFAULT_CONFIG,
};
