import hashlib, json, os, time, threading

class APIKeyManager:
    TIER_LIMITS = {'free': 100, 'pro': 5000, 'enterprise': None}

    def __init__(self, path='api_keys.json'):
        self._path = path
        self._lock = threading.Lock()
        self._store = self._load()

    def _load(self):
        try:
            with open(self._path) as f:
                return json.load(f)
        except (FileNotFoundError, json.JSONDecodeError):
            return {}

    def _save(self):
        with open(self._path, 'w') as f:
            json.dump(self._store, f, indent=2)

    def create_key(self, tier='free', label=''):
        raw = hashlib.sha256(os.urandom(32)).hexdigest()
        key = 'void_' + raw[:32]
        with self._lock:
            self._store[key] = {
                'tier': tier, 'label': label,
                'requests_today': 0, 'last_reset': time.strftime('%Y-%m-%d'),
                'created': time.strftime('%Y-%m-%dT%H:%M:%SZ')
            }
            self._save()
        return key

    def check_key(self, key):
        with self._lock:
            entry = self._store.get(key)
            if not entry:
                return False, 'invalid_key'
            today = time.strftime('%Y-%m-%d')
            if entry['last_reset'] != today:
                entry['requests_today'] = 0
                entry['last_reset'] = today
            limit = self.TIER_LIMITS.get(entry['tier'])
            if limit and entry['requests_today'] >= limit:
                return False, 'quota_exceeded'
            entry['requests_today'] += 1
            self._save()
            return True, entry['tier']

